import{urlAlphabet as scopedUrlAlphabet}from"./url-alphabet/index.js";export{urlAlphabet}from"./url-alphabet/index.js";export const random=t=>crypto.getRandomValues(new Uint8Array(t));export const customRandom=(t,o,e)=>{const r=(2<<Math.log(t.length-1)/Math.LN2)-1,n=-~(1.6*r*o/t.length);return(a=o)=>{let l="";for(;;){const o=e(n);let p=n;for(;p--;)if(l+=t[o[p]&r]||"",l.length===a)return l}}};export const customAlphabet=(t,o=21)=>customRandom(t,o,random);export const nanoid=(t=21)=>{let o="";const e=crypto.getRandomValues(new Uint8Array(t));for(;t--;)o+=scopedUrlAlphabet[63&e[t]];return o};